use num_bigint::BigInt;
use num_traits::Zero;
use crate::engine::Q;

/// Value spectrum — the amplitude component of hearing.
/// What notes are present and how loud. Part of the compound
/// soundness measurement but not the whole of hearing.
#[derive(Debug, Clone)]
pub struct ValueSpectrum {
    /// How many distinct values appear.
    pub unique_count: usize,
    /// The most frequent value and its count.
    pub dominant_value: i64,
    pub dominant_count: usize,
    /// Total cells.
    pub total_cells: usize,
    /// Dominance ratio: dominant_count / total_cells. High = uniform. Low = diverse.
    pub dominance_ratio: Q,
    /// Whether a single value fills the majority (>50%) of cells — "background" detection.
    pub has_background: bool,
    /// The background value (if has_background).
    pub background_value: i64,
    /// Number of non-background cells — the "foreground" or "objects."
    pub foreground_count: usize,
}

/// Compute the value spectrum — what the system HEARS.
pub fn compute_value_spectrum(values: &[i64]) -> ValueSpectrum {
    let total = values.len();
    if total == 0 {
        return ValueSpectrum {
            unique_count: 0, dominant_value: 0, dominant_count: 0,
            total_cells: 0, dominance_ratio: Q::zero(),
            has_background: false, background_value: 0, foreground_count: 0,
        };
    }

    // Vec with find — Core Design Law II. Delta IS the map.
    let mut counts: Vec<(i64, usize)> = Vec::new();
    for &v in values {
        match counts.iter_mut().find(|(val, _)| *val == v) {
            Some(entry) => entry.1 += 1,
            None => counts.push((v, 1)),
        }
    }

    let unique_count = counts.len();
    let &(dominant_value, dominant_count) = counts.iter()
        .max_by_key(|(_, c)| *c).unwrap();

    let dominance_ratio = Q::new(
        BigInt::from(dominant_count as i64),
        BigInt::from(total as i64),
    );
    let has_background = dominant_count * 2 > total;
    let foreground_count = if has_background { total - dominant_count } else { total };

    ValueSpectrum {
        unique_count, dominant_value, dominant_count,
        total_cells: total, dominance_ratio,
        has_background, background_value: if has_background { dominant_value } else { 0 },
        foreground_count,
    }
}
